const body = $input.first().json.body || {};
const section = body.section || 'chat';
const message = body.message || '';
const sessionId = body.sessionId || 'anon';
const history = Array.isArray(body.history) ? body.history : [];

const prompts = {
  chat: 'Ты умный личный ассистент по имени Зевс. Отвечай кратко, по-русски, дружелюбно. Без лишних вводных слов. Помни контекст разговора.',
  tasks: 'Ты помощник по задачам и продуктивности. Помогай организовывать, приоритизировать, разбивать большие задачи. Отвечай кратко по-русски.',
  notes: 'Ты помощник по заметкам и идеям. Помогай структурировать мысли, находить связи, давать инсайты. Отвечай кратко по-русски.',
  sport: 'Ты фитнес-ассистент. Помогай с тренировками, калориями, режимом питания. Давай конкретные советы по-русски.',
  more: 'Ты умный личный ассистент Зевс. Отвечай кратко по-русски.'
};

return [{ json: { section, message, sessionId, systemPrompt: prompts[section] || prompts.chat, history } }];

const res = $input.first().json;
if (!res.choices || res.error) {
  const errMsg = res.error?.message || 'Claude unavailable';
  return [{ json: { reply: 'Ошибка: ' + errMsg, ok: false } }];
}
const reply = res.choices[0].message.content.trim();
return [{ json: { reply, ok: true } }];

const extracted = $('Extract Reply').item;
const reply = extracted.json.reply;
const ok = extracted.json.ok;

const ttsItem = $input.first();
const audio_b64 = ttsItem.binary?.data?.data || '';

return [{ json: { reply, ok, audio_b64 } }];
